    double final_score = 0.0;
    for (double s : *score_parts) {
        final_score += s;
    }
    delete score_parts;

    // Step 5: Build result with temporary string
    auto* category_builder = new std::string();
    if (final_score > 1.5) *category_builder = "HIGH";
    else if (final_score > 0.5) *category_builder = "MEDIUM";
    else *category_builder = "LOW";

