// ---- OPTIMIZED VERSION: Reuses pre-allocated buffers, no heap allocations ----

class TransformPipeline {
public:
    // Pre-allocated workspace — reused across calls
    TransformPipeline() {
        temp_values_.resize(4);
        score_parts_.resize(4);
    }

    TransformResult transform_record(const RawRecord& raw) {
        // Step 1: Parse label without allocating stringstream
        parsed_label_.clear();
        size_t delim_pos = raw.label.find('_');
        if (delim_pos != std::string::npos) {
            parsed_label_.assign(raw.label, 0, delim_pos);
        } else {
            parsed_label_ = raw.label;
        }

        // Step 2: Compute magnitude directly from raw data (no temp vector needed)
        double sum_sq = 0.0;
        for (int i = 0; i < 4; ++i) {
            sum_sq += raw.values[i] * raw.values[i];
        }
        double magnitude = std::sqrt(sum_sq);

        // Step 3: Normalize in-place into reusable buffer
        if (magnitude > 0.0) {
            double inv_mag = 1.0 / magnitude;
            for (int i = 0; i < 4; ++i) {
                temp_values_[i] = raw.values[i] * inv_mag;
            }
        } else {
            for (int i = 0; i < 4; ++i) {
                temp_values_[i] = 0.0;
            }
        }

        // Step 4: Compute score directly — no temporary containers
        double final_score = 0.0;
        for (int i = 0; i < 4; ++i) {
            final_score += temp_values_[i] * (i + 1);
        }

        // Step 5: Build result — use string_view-like logic, assign directly
        TransformResult result;
        result.id = raw.id;
        result.score = final_score;
        result.is_valid = (magnitude > 0.001);

        if (final_score > 1.5) result.category = "HIGH";
        else if (final_score > 0.5) result.category = "MEDIUM";
        else result.category = "LOW";

        return result;
    }

private:
    std::vector<double> temp_values_;
    std::vector<double> score_parts_;
    std::string parsed_label_;
};

